    uint32_t totalLength;
    uint32_t dimSize;
    uint32_t tileLength;
    uint32_t blockDim;
};

static inline uint32_t AlignDown(uint32_t x, uint32_t a) {
    return (x / a) * a;
}

static inline uint32_t CeilDiv(uint32_t a, uint32_t b) {
    return (a + b - 1u) / b;
}

static ge::graphStatus TilingFunc(gert::TilingContext *context) {
    Ca6k00518CustomTilingData tiling;

    const gert::Shape& originShape = context->GetInputShape(0)->GetOriginShape();
    uint32_t totalLength = static_cast<uint32_t>(originShape.GetShapeSize());

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    int64_t dim = attrs->GetAttrPointer<int64_t>(0)[0];
    int64_t rank = originShape.GetDimNum();
    if (dim < 0) dim += rank;
    uint32_t dimSize = static_cast<uint32_t>(originShape.GetDim(dim));

    uint32_t numVectors = totalLength / dimSize;

    uint32_t maxTile = UB_BUDGET_BYTES / (2 * sizeof(float));
    maxTile = AlignDown(maxTile, ALIGN_ELEMS);
    if (maxTile < ALIGN_ELEMS) maxTile = ALIGN_ELEMS;
    if (maxTile > HARD_CAP_ELEMS) maxTile = AlignDown(HARD_CAP_ELEMS, ALIGN_ELEMS);
    uint32_t tileLength = maxTile;
    if (dimSize < tileLength) {
        tileLength = AlignDown(dimSize, ALIGN_ELEMS);
        if (tileLength == 0) tileLength = dimSize;
    }

    uint32_t blockDim = numVectors;
    if (blockDim < 8u) blockDim = 8u;
    if (blockDim > 24u) blockDim = 24u;

    context->SetBlockDim(blockDim);

    tiling.totalLength = totalLength;
    tiling.dimSize = dimSize;
    tiling.tileLength = tileLength;
    tiling.blockDim = blockDim;

    std::memcpy(context->GetRawTilingData()->GetData(), &tiling, sizeof(tiling));
    context->GetRawTilingData()->SetDataSize(sizeof(tiling));

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

