#include "kernel_operator.h"
#include <cfloat>

struct Ca6k00518CustomTilingData {
    uint32_t totalLength;
    uint32_t dimSize;
    uint32_t tileLength;
    uint32_t blockDim;
};

constexpr int32_t BUFFER_NUM = 2;

class KernelCa6k00518Custom {
public:
    __aicore__ inline KernelCa6k00518Custom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength, uint32_t dimSize,
                                uint32_t tileLength)
    {
        totalLen_ = totalLength;
        dimSize_ = dimSize;
        tileLen_ = tileLength;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue_, 2, tileLen_ * sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (totalLen_ == 0 || dimSize_ == 0 || tileLen_ == 0) return;

        const uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        uint32_t numVectors = totalLen_ / dimSize_;

        for (uint32_t vecIdx = blockIdx; vecIdx < numVectors; vecIdx += blockNum) {
            uint32_t baseOff = vecIdx * dimSize_;

            // First pass: compute sum of exp(-x) using numerically stable shift
            // shift = max(x) for softmin: we want to avoid overflow in exp(-x)
            float shift = -FLT_MAX;
            for (uint32_t tileOff = 0; tileOff < dimSize_; tileOff += tileLen_) {
                uint32_t curLen = (tileOff + tileLen_ <= dimSize_) ? tileLen_ : (dimSize_ - tileOff);
                AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
                AscendC::DataCopy(xLocal, xGm_[baseOff + tileOff], curLen);
                inQueueX_.EnQue(xLocal);
                xLocal = inQueueX_.DeQue<float>();
                AscendC::LocalTensor<float> maxLocal = tmpQueue_.AllocTensor<float>();
                AscendC::ReduceMax(maxLocal, xLocal, curLen);
                float m = maxLocal.GetValue(0);
                if (m > shift) shift = m;
                tmpQueue_.FreeTensor(maxLocal);
                inQueueX_.FreeTensor(xLocal);
            }

            // Second pass: compute exp(-(x - shift)) and accumulate sum
            float sum = 0.0f;
            for (uint32_t tileOff = 0; tileOff < dimSize_; tileOff += tileLen_) {
                uint32_t curLen = (tileOff + tileLen_ <= dimSize_) ? tileLen_ : (dimSize_ - tileOff);
                AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
                AscendC::DataCopy(xLocal, xGm_[baseOff + tileOff], curLen);
                inQueueX_.EnQue(xLocal);
                xLocal = inQueueX_.DeQue<float>();
                AscendC::LocalTensor<float> diff = tmpQueue_.AllocTensor<float>();
                AscendC::Sub(diff, xLocal, shift, curLen);
                inQueueX_.FreeTensor(xLocal);
                AscendC::LocalTensor<float> negDiff = tmpQueue_.AllocTensor<float>();
                AscendC::Neg(negDiff, diff, curLen);
                tmpQueue_.FreeTensor(diff);
                AscendC::LocalTensor<float> expLocal = tmpQueue_.AllocTensor<float>();
                AscendC::Exp(expLocal, negDiff, curLen);
                tmpQueue_.FreeTensor(negDiff);
                AscendC::LocalTensor<float> sumLocal = tmpQueue_.AllocTensor<float>();
                AscendC::ReduceSum(sumLocal, expLocal, curLen);
                sum += sumLocal.GetValue(0);
                tmpQueue_.FreeTensor(sumLocal);
                tmpQueue_.FreeTensor(expLocal);
            }

            // Third pass: normalize and write out
            float invSum = 1.0f / sum;
            for (uint32_t tileOff = 0; tileOff < dimSize_; tileOff += tileLen_) {
                uint32_t curLen = (tileOff + tileLen_ <= dimSize_) ? tileLen_ : (dimSize_ - tileOff);
                AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
                AscendC::DataCopy(xLocal, xGm_[baseOff + tileOff], curLen);
                inQueueX_.EnQue(xLocal);
                xLocal = inQueueX_.DeQue<float>();
                AscendC::LocalTensor<float> diff = tmpQueue_.AllocTensor<float>();
                AscendC::Sub(diff, xLocal, shift, curLen);
                inQueueX_.FreeTensor(xLocal);
                AscendC::LocalTensor<float> negDiff = tmpQueue_.AllocTensor<float>();
                AscendC::Neg(negDiff, diff, curLen);
                tmpQueue_.FreeTensor(diff);
                AscendC::LocalTensor<float> expLocal = outQueueY_.AllocTensor<float>();
                AscendC::Exp(expLocal, negDiff, curLen);
                tmpQueue_.FreeTensor(negDiff);
                AscendC::Muls(expLocal, expLocal, invSum, curLen);
                outQueueY_.EnQue(expLocal);
                expLocal = outQueueY_.DeQue<float>();
                AscendC::DataCopy(yGm_[baseOff + tileOff], expLocal, curLen);
                outQueueY_.FreeTensor(expLocal);
            }
        }
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 2> tmpQueue_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalLen_ {0};
    uint32_t dimSize_ {0};
    uint32_t tileLen_ {0};
};

extern "C" __global__ __aicore__ void ca6k_00518_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    const Ca6k00518CustomTilingData *td = reinterpret_cast<const Ca6k00518CustomTilingData*>(tiling);
    KernelCa6k00518Custom op;
    op.Init(x, y, td->totalLength, td->dimSize, td->tileLength);
    op.Process();
}
